import{_ as n,o as s,c as l,ae as e}from"./chunks/framework.jfJLTIcL.js";const u=JSON.parse('{"title":"Playground 模型对比测试平台设计","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/specs/2026-04-07-playground-design.md","filePath":"superpowers/specs/2026-04-07-playground-design.md","lastUpdated":1775492272000}'),t={name:"superpowers/specs/2026-04-07-playground-design.md"};function i(p,a,r,o,d,h){return s(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="playground-模型对比测试平台设计" tabindex="-1">Playground 模型对比测试平台设计 <a class="header-anchor" href="#playground-模型对比测试平台设计" aria-label="Permalink to &quot;Playground 模型对比测试平台设计&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>一个面向开发者设计的模型对比测试平台，支持同时对多个 AI 模型发起独立 Prompt 测试，快速对比输出结果。</p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><ul><li><strong>Prompt 对比</strong>：输入同一个 Prompt，并行对比多个模型的输出</li><li><strong>模型参数调试</strong>：配置 Think 开关、温度、Top_p 等参数</li><li><strong>混合模型支持</strong>：同时支持 Ollama 本地模型和 API 模型（OpenAI、Anthropic 等）</li></ul><h2 id="用户场景" tabindex="-1">用户场景 <a class="header-anchor" href="#用户场景" aria-label="Permalink to &quot;用户场景&quot;">​</a></h2><ul><li>开发者调试：快速对比不同模型对同一 Prompt 的输出质量</li><li>单轮独立 Prompt，不支持多轮对话链</li></ul><h2 id="布局结构" tabindex="-1">布局结构 <a class="header-anchor" href="#布局结构" aria-label="Permalink to &quot;布局结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  [Logo]  Playground                              [Ollama状态] [API状态] │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  Prompt 输入框 (多行，monospace字体)                                   │</span></span>
<span class="line"><span>│  ┌─────────────────────────────────────────────────────────────┐    │</span></span>
<span class="line"><span>│  │ 请输入你的测试 Prompt...                                      │    │</span></span>
<span class="line"><span>│  └─────────────────────────────────────────────────────────────┘    │</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>│  模型选择 (可多选)                参数面板                            │</span></span>
<span class="line"><span>│  ☑ Gemma4-e4b (Ollama)         ☑ Think  [温度: 0.7] [Top_p: 0.9]   │</span></span>
<span class="line"><span>│  ☐ Qwen3 (API)                 [系统提示: 可选输入框]                │</span></span>
<span class="line"><span>│  ☐ DeepSeek (API)                                                 [运行] │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  ┌──────────────┐  ┌──────────────┐  ┌──────────────┐              │</span></span>
<span class="line"><span>│  │ Gemma4-e4b   │  │ Qwen3        │  │ DeepSeek     │              │</span></span>
<span class="line"><span>│  │ (Ollama)     │  │ (API)        │  │ (API)        │              │</span></span>
<span class="line"><span>│  │              │  │              │  │              │              │</span></span>
<span class="line"><span>│  │ Thinking:    │  │ Thinking:    │  │ Thinking:    │              │</span></span>
<span class="line"><span>│  │ [输出内容]   │  │ [输出内容]   │  │ [输出内容]   │              │</span></span>
<span class="line"><span>│  │              │  │              │  │              │              │</span></span>
<span class="line"><span>│  │ Token: 123   │  │ Token: 234   │  │ Token: 345   │              │</span></span>
<span class="line"><span>│  │ Time: 1.2s   │  │ Time: 2.1s   │  │ Time: 3.0s   │              │</span></span>
<span class="line"><span>│  └──────────────┘  └──────────────┘  └──────────────┘              │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="组件说明" tabindex="-1">组件说明 <a class="header-anchor" href="#组件说明" aria-label="Permalink to &quot;组件说明&quot;">​</a></h2><h3 id="_1-头部导航栏" tabindex="-1">1. 头部导航栏 <a class="header-anchor" href="#_1-头部导航栏" aria-label="Permalink to &quot;1. 头部导航栏&quot;">​</a></h3><ul><li>Logo + 产品名称</li><li>Ollama 连接状态指示（绿色/红色）</li><li>API 服务状态指示</li></ul><h3 id="_2-prompt-输入区" tabindex="-1">2. Prompt 输入区 <a class="header-anchor" href="#_2-prompt-输入区" aria-label="Permalink to &quot;2. Prompt 输入区&quot;">​</a></h3><ul><li>多行文本输入框</li><li>Monospace 字体</li><li>支持长文本输入</li></ul><h3 id="_3-模型选择器" tabindex="-1">3. 模型选择器 <a class="header-anchor" href="#_3-模型选择器" aria-label="Permalink to &quot;3. 模型选择器&quot;">​</a></h3><ul><li>Checkbox 分组显示</li><li>Ollama 模型和 API 模型分组</li><li>支持多选</li></ul><h3 id="_4-参数面板" tabindex="-1">4. 参数面板 <a class="header-anchor" href="#_4-参数面板" aria-label="Permalink to &quot;4. 参数面板&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td>Think 开关</td><td>Checkbox</td><td>开启</td></tr><tr><td>温度 (Temperature)</td><td>Slider/Input</td><td>0.7</td></tr><tr><td>Top_p</td><td>Slider/Input</td><td>0.9</td></tr><tr><td>系统提示词</td><td>Textarea</td><td>可选</td></tr></tbody></table><h3 id="_5-运行按钮" tabindex="-1">5. 运行按钮 <a class="header-anchor" href="#_5-运行按钮" aria-label="Permalink to &quot;5. 运行按钮&quot;">​</a></h3><ul><li>主按钮样式</li><li>点击后触发所有选中模型并行执行</li><li>运行中显示 loading 状态</li></ul><h3 id="_6-输出卡片" tabindex="-1">6. 输出卡片 <a class="header-anchor" href="#_6-输出卡片" aria-label="Permalink to &quot;6. 输出卡片&quot;">​</a></h3><p>每个模型对应一张卡片，显示：</p><ul><li>模型名称 + 来源标签</li><li>输出内容（Markdown 渲染）</li><li>Token 消耗数量</li><li>响应耗时</li></ul><h3 id="_7-状态指示器" tabindex="-1">7. 状态指示器 <a class="header-anchor" href="#_7-状态指示器" aria-label="Permalink to &quot;7. 状态指示器&quot;">​</a></h3><ul><li>Ollama：未连接/已连接</li><li>API：未配置/已配置</li></ul><h2 id="数据流" tabindex="-1">数据流 <a class="header-anchor" href="#数据流" aria-label="Permalink to &quot;数据流&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入 Prompt</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>用户选择模型 + 配置参数</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>点击&quot;运行&quot; → 并行请求多个模型</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>各自返回输出 → 更新对应输出卡片</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>展示结果（输出 + 性能数据）</span></span></code></pre></div><h2 id="错误处理" tabindex="-1">错误处理 <a class="header-anchor" href="#错误处理" aria-label="Permalink to &quot;错误处理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>错误场景</th><th>处理方式</th></tr></thead><tbody><tr><td>Ollama 未启动</td><td>提示&quot;请先启动 Ollama&quot;，禁用 Ollama 模型</td></tr><tr><td>API Key 无效</td><td>显示认证错误，不阻塞其他模型</td></tr><tr><td>单模型请求失败</td><td>对应卡片显示错误信息，其他模型正常显示</td></tr></tbody></table><h2 id="技术实现要点" tabindex="-1">技术实现要点 <a class="header-anchor" href="#技术实现要点" aria-label="Permalink to &quot;技术实现要点&quot;">​</a></h2><ul><li>前端框架：React + TypeScript</li><li>状态管理：Zustand（轻量级）</li><li>Ollama 通信：REST API (<code>localhost:11434</code>)</li><li>API 模型：统一接口适配不同 provider</li><li>并行请求：Promise.allSettled（单个失败不阻塞其他）</li></ul><h2 id="设计原则" tabindex="-1">设计原则 <a class="header-anchor" href="#设计原则" aria-label="Permalink to &quot;设计原则&quot;">​</a></h2><ul><li>效率优先：开发者追求快速对比，界面简洁直接</li><li>信息完整：输出内容 + 性能数据同时展示</li><li>容错友好：单模型失败不影响整体测试流程</li></ul>`,33)])])}const m=n(t,[["render",i]]);export{u as __pageData,m as default};
